import pymysql
from urllib.parse import unquote_plus

def lambda_handler(event, context):
    db_host = 'your-rds-host'
    db_username = 'your-rds-username'
    db_password = 'your-rds-password'
    db_name = 'your-rds-database'

    conn = pymysql.connect(
        host=db_host,
        user=db_username,
        password=db_password,
        database=db_name
    )

    cur = conn.cursor()

    search_params = event.get('queryStringParameters', {})

    query = "SELECT * FROM products"
    params = []

    if 'name' in search_params:
        query += " WHERE name LIKE %s"
        params.append(f"%{unquote_plus(search_params['name'])}%")

    if 'category' in search_params:
        query += " AND category = %s"
        params.append(unquote_plus(search_params['category']))

    if 'price' in search_params:
        query += " AND price BETWEEN %s AND %s"
        params.extend([float(unquote_plus(search_params['price'])), float(unquote_plus(search_params['price']))])

    cur.execute(query, tuple(params))

    products = cur.fetchall()

    conn.close()

    return {
        'statusCode': 200,
        'body': {'products': products}
    }